function fillRow(PDO $pdo, string $table, int $id, array $data): void {
    $sets=[]; $params=[];
    foreach ($data as $column=>$value) { $sets[]="`$column` = CASE WHEN `$column` IS NULL OR TRIM(`$column`) = '' THEN ? ELSE `$column` END"; $params[]=$value; }
    $params[]=$id;
    $pdo->prepare("UPDATE `$table` SET ".implode(', ',$sets).' WHERE id = ?')->execute($params);
}

$pdo->beginTransaction();
try {
    foreach ($products as $id=>$data) fillRow($pdo,'products',$id,$data);
    foreach ($services as $id=>$v) fillRow($pdo,'services',$id,array_combine(['name_en','short_description_en','description_en','meta_title_en','meta_description_en'],$v));
    foreach ($postText as $id=>$v) fillRow($pdo,'posts',$id,array_combine(['title_en','excerpt_en','category_en','meta_title_en','meta_description_en','meta_keywords_en','content_en'],$v));
    foreach ([1=>'Cacao Beans',2=>'Cacao Derivatives'] as $id=>$name) fillRow($pdo,'categories',$id,['name_en'=>$name]);
    $stmt=$pdo->prepare("INSERT INTO settings (setting_key,setting_value) VALUES (?,?) ON DUPLICATE KEY UPDATE setting_value=IF(setting_value IS NULL OR TRIM(setting_value)='',VALUES(setting_value),setting_value)");
    foreach ($about as $key=>$value) $stmt->execute([$key,$value]);
    $pdo->commit();
    echo "Traducciones EN completadas sin sobrescribir valores existentes.\n";
} catch (Throwable $e) {
    if ($pdo->inTransaction()) $pdo->rollBack();
    fwrite(STDERR,"No se aplicaron cambios: {$e->getMessage()}\n"); exit(1);
}
